// AbstractExpression: every node exposes interpret(context)

// Terminal expression — a numeric literal
class NumberExpression {
  constructor(value) { this.value = value; }
  interpret(_context) { return this.value; }
}

// Terminal expression — a variable looked up in the context
class VariableExpression {
  constructor(name) { this.name = name; }
  interpret(context) {
    if (!(this.name in context)) {
      throw new Error(`Unknown variable: ${this.name}`);
    }
    return context[this.name];
  }
}

// Nonterminal expressions — compose sub-expressions
class AddExpression {
  constructor(left, right) { this.left = left; this.right = right; }
  interpret(context) {
    return this.left.interpret(context) + this.right.interpret(context);
  }
}

class SubtractExpression {
  constructor(left, right) { this.left = left; this.right = right; }
  interpret(context) {
    return this.left.interpret(context) - this.right.interpret(context);
  }
}

// Usage — represents: x + 5 - 2
const tree = new SubtractExpression(
  new AddExpression(
    new VariableExpression('x'),
    new NumberExpression(5),
  ),
  new NumberExpression(2),
);

const context = { x: 10 };
console.log(tree.interpret(context)); // 13

