from __future__ import annotations
from abc import ABC, abstractmethod

Context = dict[str, int]


class Expression(ABC):
    """AbstractExpression"""
    @abstractmethod
    def interpret(self, context: Context) -> int: ...


class NumberExpression(Expression):
    """Terminal expression — a numeric literal."""
    def __init__(self, value: int) -> None:
        self.value = value

    def interpret(self, context: Context) -> int:
        return self.value


class VariableExpression(Expression):
    """Terminal expression — a variable."""
    def __init__(self, name: str) -> None:
        self.name = name

    def interpret(self, context: Context) -> int:
        if self.name not in context:
            raise ValueError(f'Unknown variable: {self.name}')
        return context[self.name]


class AddExpression(Expression):
    """Nonterminal expression."""
    def __init__(self, left: Expression, right: Expression) -> None:
        self.left, self.right = left, right

    def interpret(self, context: Context) -> int:
        return self.left.interpret(context) + self.right.interpret(context)


class SubtractExpression(Expression):
    """Nonterminal expression."""
    def __init__(self, left: Expression, right: Expression) -> None:
        self.left, self.right = left, right

    def interpret(self, context: Context) -> int:
        return self.left.interpret(context) - self.right.interpret(context)


# Usage — represents: x + 5 - 2
tree = SubtractExpression(
    AddExpression(VariableExpression('x'), NumberExpression(5)),
    NumberExpression(2),
)

print(tree.interpret({'x': 10}))  # 13
